{"content":"package com.pinterest.ktlint.rule.engine.api

import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import org.assertj.core.api.Assertions.assertThat
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.junit.jupiter.api.Test

class FormatRerunTest {
    @Test
    fun `Given a rule that depends on another rule's correction then rerun format`() {
        var rule1Executed = 0
        var rule2Executed = 0
        val rule1Id = RuleId("test:rule-1")
        val rule2Id = RuleId("test:rule-2")

        val ruleProvider1 = RuleProvider {
            object : Rule(rule1Id, about = About()) {
                override fun beforeVisitChildNodes(
                    node: ASTNode,
                    autoCorrect: Boolean,
                    emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
                ) {
                    rule1Executed++
                    if (node.text == "foo") {
                        emit(node.startOffset, "Replace foo with bar", true)
                        if (autoCorrect) {
                            (node as org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafElement).replaceWithText("bar")
                        }
                    }
                }
            }
        }

        val ruleProvider2 = RuleProvider {
            object : Rule(rule2Id, about = About()) {
                override fun beforeVisitChildNodes(
                    node: ASTNode,
                    autoCorrect: Boolean,
                    emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
                ) {
                    rule2Executed++
                    if (node.text == "bar") {
                        emit(node.startOffset, "Replace bar with baz", true)
                        if (autoCorrect) {
                            (node as org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafElement).replaceWithText("baz")
                        }
                    }
                }
            }
        }

        val code = "val x = \"foo\""
        // Initially: foo
        // Run 1: Rule 1 changes foo to bar. Rule 2 sees bar? 
        // Wait, Rule 2 might run before Rule 1 depending on order.
        // If Rule 2 runs before Rule 1:
        // Run 1: Rule 2 sees foo (no change). Rule 1 changes foo to bar.
        // Run 2: Rule 2 changes bar to baz. Rule 1 sees baz (no change).
        // Run 3: No more changes.

        val engine = KtLintRuleEngine(
            ruleProviders = setOf(ruleProvider1, ruleProvider2)
        )
        val formattedCode = engine.format(Code.fromSnippet(code))

        assertThat(formattedCode).contains("baz")
        // Rule 1 should have run at least twice (initial + 1 rerun)
        // Rule 2 should have run at least twice (initial + 1 rerun)
        // Actually it might run 3 times because it only stops when a full run has no mutations.
        assertThat(rule1Executed).isGreaterThan(1)
        assertThat(rule2Executed).isGreaterThan(1)
    }

    @Test
    fun `Limit reruns to prevent infinite loop`() {
        var ruleExecuted = 0
        val ruleId = RuleId("test:infinite-rule")
        val ruleProvider = RuleProvider {
            object : Rule(ruleId, about = About()) {
                private var toggle = true
                override fun beforeVisitChildNodes(
                    node: ASTNode,
                    autoCorrect: Boolean,
                    emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
                ) {
                    if (node.text == "foo" || node.text == "bar") {
                        ruleExecuted++
                        val nextText = if (node.text == "foo") "bar" else "foo"
                        emit(node.startOffset, "Toggle foo/bar", true)
                        if (autoCorrect) {
                            (node as org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafElement).replaceWithText(nextText)
                        }
                    }
                }
            }
        }

        val code = "val x = \"foo\""
        val engine = KtLintRuleEngine(
            ruleProviders = setOf(ruleProvider)
        )
        val formattedCode = engine.format(Code.fromSnippet(code))

        // Initial run + 3 reruns = 4 runs total.
        // Each run visits "foo" or "bar".
        // Wait, the rule is executed on ALL nodes.
        // But for our specific node:
        // Run 1: foo -> bar
        // Run 2: bar -> foo
        // Run 3: foo -> bar
        // Run 4: bar -> foo
        // Total 4 runs.

        // Wait, how many times is beforeVisitChildNodes called? 
        // On the whole tree.
        // For simplicity, let's just count how many times it was called for the string leaf.
        // "val", " ", "x", " ", "=", " ", "\"foo\"" -> actually "\"" "foo" "\"" 

        // Anyway, the number of format runs should be 4.
        // Let's check ruleExecuted.
        assertThat(ruleExecuted).isEqualTo(4)
    }
}
